void ApplyMigrations(AppDbContext db)
{
    // EF Core 9: Migrate() now manages its own transactions internally
    // and throws if called inside a user-opened transaction.
    var strategy = db.Database.CreateExecutionStrategy();
    strategy.Execute(() =>
    {
        db.Database.Migrate();
    });
}

